describe('getTasksBlockedBy', () => {
  it('returns tasks blocked by a failed task', () => {
    registerTask('t1', 'backend-system-architect', 85);
    registerTask('t2', 'test-generator', 80, undefined, undefined, ['t1']);
    updateTaskStatus('t1', 'failed');
    const blocked = getTasksBlockedBy('t1');
    expect(blocked).toHaveLength(1);
    expect(blocked[0].taskId).toBe('t2');
  });

  it('returns empty array when nothing is blocked', () => {
    registerTask('t1', 'backend-system-architect', 85);
    expect(getTasksBlockedBy('t1')).toEqual([]);
  });
});

describe('getOrphanedTasks', () => {
  it('finds orphaned tasks where all blockers failed', () => {
    registerTask('t1', 'backend-system-architect', 85);
    registerTask('t2', 'test-generator', 80, undefined, undefined, ['t1']);
    updateTaskStatus('t1', 'failed');
    expect(getOrphanedTasks()).toHaveLength(1);
    expect(getOrphanedTasks()[0].taskId).toBe('t2');
  });

  it('returns empty when no tasks have failed', () => {
    registerTask('t1', 'backend-system-architect', 85);
    registerTask('t2', 'test-generator', 80, undefined, undefined, ['t1']);
    expect(getOrphanedTasks()).toEqual([]);
  });

  it('does not include tasks with some non-failed blockers', () => {
    registerTask('t1', 'backend-system-architect', 85);
    registerTask('t2', 'test-generator', 80);
    registerTask('t3', 'debug-investigator', 70, undefined, undefined, ['t1', 't2']);
    updateTaskStatus('t1', 'failed');
    expect(getOrphanedTasks()).toEqual([]);
  });
});

