describe('cleanupOldTasks', () => {
  function backdateTask(taskIdx: number, hoursAgo: number) {
    const reg = readReg();
    reg.tasks[taskIdx].createdAt = new Date(Date.now() - hoursAgo * 3600000).toISOString();
    fs.writeFileSync(regPath(), JSON.stringify(reg, null, 2));
  }

  function backdatePipeline(pipeIdx: number, hoursAgo: number) {
    const reg = readReg();
    reg.pipelines[pipeIdx].startedAt = new Date(Date.now() - hoursAgo * 3600000).toISOString();
    fs.writeFileSync(regPath(), JSON.stringify(reg, null, 2));
  }

  it('removes old completed tasks but keeps active ones', () => {
    registerTask('t1', 'backend-system-architect', 85);
    registerTask('t2', 'test-generator', 80);
    updateTaskStatus('t1', 'completed');
    backdateTask(0, 48);
    backdateTask(1, 48);
    cleanupOldTasks(24 * 3600000);
    const after = readReg();
    expect(after.tasks).toHaveLength(1);
    expect(after.tasks[0].taskId).toBe('t2');
  });

  it('removes old completed pipelines but keeps running ones', () => {
    registerPipeline(makePipeline({ pipelineId: 'p1', status: 'completed' }));
    registerPipeline(makePipeline({ pipelineId: 'p2', status: 'running' }));
    backdatePipeline(0, 48);
    backdatePipeline(1, 48);
    cleanupOldTasks(24 * 3600000);
    const after = readReg();
    expect(after.pipelines).toHaveLength(1);
    expect(after.pipelines[0].pipelineId).toBe('p2');
  });
});
